// function prepareTableauVars (corrigée pour nouvelle structure enrichedVars)

let enrichedVars = global.get("enrichedVars", "file") || {};
console.log("Données chargées depuis global.json :", enrichedVars);

let tableauPourUI = [];
flow.set("varSelected", "");

// On parcourt toutes les variables globales
Object.entries(enrichedVars).forEach(([nomVarG, e]) => {
    if (!nomVarG || !e || typeof e !== "object") return;  // Ignore les entrées invalides

    let props = e.proprietes || [];   // ✅ nouvelle structure
    let proprieteResume = props.length > 0
        ? props.map(p => `${p.nomP} (${p.typeP})`).join(", ")
        : "(Aucune propriété définie)";

    const instances = e.instances || ["*"];

    tableauPourUI.push({
        nomVarG,
        abbrVarG: e.abbrVarG || "",
        instances: instances.join(", "),
        proprietes: proprieteResume,
        description: e.descriptionVarG || ""
    });
});

msg.payload = tableauPourUI;
return msg;

// === Infos générales enrichedVars (fusion avec sauvVarSelected) ===

// Gère création/modification d'une variable
// - contrôle du nom
// - initialisation instances (ajout '*' oblig.)
// - initialise proprietes si vide
let enrichedVars = global.get("enrichedVars", "file") || {};
let varSelected = flow.get("varSelected") || null;
let formData = msg.payload;

if (!formData || !formData.nomVarG) {
    msg.info = "❌ Formulaire incomplet ou variable non spécifiée.";
    return null;
}

// --- Normalisation du nom ---
let newName = formData.nomVarG.trim();

// Vérification caractères autorisés
if (!/^[A-Za-z0-9_]+$/.test(newName)) {
    msg.info = `❌ Nom de variable invalide ('${newName}'). Utilise uniquement lettres, chiffres ou '_'`;
    return null;
}

let oldName = varSelected;

// --- Cas création ---
if (!enrichedVars[oldName]) {
    if (enrichedVars[newName]) {
        msg.info = `❌ Impossible de créer '${newName}', une variable existe déjà avec ce nom.`;
        return null;
    }

    enrichedVars[newName] = {
        nomVarG: newName,
        abbrVarG: formData.abbrVarG || "",
        instances: formData.instances
            ? formData.instances.split(",").map(e => e.trim())
            : ["*"],
        descriptionVarG: formData.descriptionVarG || "",
        dateUpdateVarG: new Date().toISOString(),
        proprietes: [
            {
                nomP: "defautProp",     // ✅ CORRIGÉ : nomP (pas nom)
                abbrP: "def",           // ✅ CORRIGÉ : abbrP (pas abbr)
                typeP: "string",        // ✅ CORRIGÉ : typeP (pas type)
                schema: null,
                valeurs: { "*": "" }
            }
        ]
    };

    flow.set("varSelected", newName);

    // Protection contre l'écriture de données vides
    if (!enrichedVars || Object.keys(enrichedVars).length === 0) {
        node.warn("⚠️ Tentative d'écriture d'un enrichedVars vide ignorée");
    } else {
        global.set("enrichedVars", enrichedVars, "file");
    }

    msg.payload = newName;
    msg.info = `✅ Nouvelle variable créée : ${newName}`;
    return msg;
}

// --- Cas modification ---
let current = enrichedVars[oldName];

// Si le nom change
if (oldName !== newName) {
    if (enrichedVars[newName]) {
        msg.info = `⚠️ '${newName}' existe déjà, impossible de renommer '${oldName}'`;
        return null;
    }

    enrichedVars[newName] = current;
    delete enrichedVars[oldName];
    flow.set("varSelected", newName);
}

// --- Synchronisation des instances ---
let newInstances = formData.instances
    ? formData.instances.split(",").map(e => e.trim())
    : current.instances;
let oldInstances = current.instances || [];

// Synchroniser les valeurs pour toutes les propriétés
(current.proprietes || []).forEach(prop => {
    prop.valeurs = prop.valeurs || {};

    // Ajouter les nouvelles instances avec valeur par défaut
    newInstances.forEach(inst => {
        if (!(inst in prop.valeurs)) {
            switch (prop.type) {
                case "boolean": prop.valeurs[inst] = false; break;
                case "int":
                case "number": prop.valeurs[inst] = 0; break;
                case "array": prop.valeurs[inst] = []; break;
                case "object": prop.valeurs[inst] = {}; break;
                case "date": prop.valeurs[inst] = new Date().toISOString().slice(0, 10); break;
                default: prop.valeurs[inst] = "";
            }
        }
    });

    // Supprimer les valeurs des instances disparues
    oldInstances.forEach(inst => {
        if (!newInstances.includes(inst)) {
            delete prop.valeurs[inst];
        }
    });
});

// --- Mise à jour des infos générales ---
enrichedVars[newName || oldName] = {
    ...enrichedVars[newName || oldName],
    nomVarG: newName,
    abbrVarG: formData.abbrVarG || enrichedVars[newName || oldName].abbrVarG,
    instances: newInstances,
    descriptionVarG: formData.descriptionVarG || enrichedVars[newName || oldName].descriptionVarG,
    dateUpdateVarG: new Date().toISOString()
};
// Protection contre l'écriture de données vides
if (!enrichedVars || Object.keys(enrichedVars).length === 0) {
    node.warn("⚠️ Tentative d'écriture d'un enrichedVars vide ignorée");
    // Ne pas faire le set, mais continuer le flow si nécessaire
} else {
    global.set("enrichedVars", enrichedVars, "file");
}

msg.payload = newName || oldName;
msg.info = `✅ Variable ${oldName !== newName ? `renommée de '${oldName}' en '${newName}' et ` : ""}mise à jour.`;
return msg;

// 🔹 recupVarSelected
// - Détermine si on sélectionne une variable existante ou si on crée une nouvelle
// - Met à jour flow.varSelected
// - Fournit msg.info et msg.payload adaptés

let enrichedVars = global.get("enrichedVars", "file") || {};
let listeVars = Object.keys(enrichedVars);
let varSelected = null;

// 1) Cas bouton "Ajouter une VarG"
if (msg.topic === "newVarG") {
    varSelected = "new";
}
// 2) Cas sélection dans la table
else {
    varSelected = msg.payload?.row?.nomVarG || msg.payload?.nomVarG || null;
}

// 3) Vérification : aucune sélection
if (!varSelected) {
    msg.info = (listeVars.length === 0)
        ? "⚠️ Aucune variable existante dans enrichedVars."
        : "⚠️ Aucune variable sélectionnée pour édition.";
    return msg;  // on sort proprement
}

// 4) Stockage de la sélection
flow.set("varSelected", varSelected);

// 5) Message d'info
msg.info = (varSelected === "new")
    ? "➕ Création d'une nouvelle variable."
    : `✅ Vous êtes sur la variable : ${varSelected}`;

// 6) Retour
msg.payload = varSelected;
return msg;

// 🔹 prepareFormVarSelected
// - Prépare le formulaire Form_Var_Modif selon varSelected
// - Gère : création nouvelle variable, édition variable existante, cas vide

let enrichedVars = global.get("enrichedVars", "file") || {};
let varSelected = flow.get("varSelected") || null;

// 1) Cas création d'une nouvelle variable
if (varSelected === "new") {
    msg.payload = {
        nomVarG: "",
        abbrVarG: "",
        instances: "*",  // instance par défaut obligatoire
        descriptionVarG: "- Objectif(s): - Origine: - Autres : ",
        dateUpdateVarG: new Date().toISOString()
    };
    msg.topic = "newVarG";
    msg.info = "➕ Création d'une nouvelle variable.";
    return msg;
}

// 2) Cas édition d'une variable existante
if (varSelected && enrichedVars[varSelected]) {
    const selected = enrichedVars[varSelected];
    msg.payload = {
        nomVarG: selected.nomVarG || varSelected,
        abbrVarG: selected.abbrVarG || "",
        instances: selected.instances ? selected.instances.join(", ") : "*",
        descriptionVarG: selected.descriptionVarG || "",
        dateUpdateVarG: selected.dateUpdateVarG || new Date().toISOString()
    };
    msg.info = `✏️ Édition de la variable '${varSelected}'.`;
    return msg;
}

// 3) Cas aucun varSelected valide
if (Object.keys(enrichedVars).length === 0) {
    msg.info = "⚠️ Aucune variable définie. Utilisez 'Ajouter une VarG' pour commencer.";
} else {
    msg.info = "⚠️ Aucune variable sélectionnée pour édition.";
}

// Payload neutre pour éviter un crash du formulaire
msg.payload = {
    nomVarG: "",
    abbrVarG: "",
    instances: "",
    descriptionVarG: "",
    dateUpdateVarG: new Date().toISOString()
};
return msg;

/* Le nœud ui-notification envoie un message avec msg.payload contenant :
   - "confirm_clicked" si l'utilisateur clique sur "✅ Supprimer".
   - "dismiss_clicked" si l'utilisateur clique sur "❌ Annuler".
*/
if (msg.payload === "confirm_clicked") {
    const varToDelete = flow.get("pendingDeletion");

    if (!varToDelete) {
        msg.info = "⚠️ Aucune variable en attente de suppression.";
        return msg;
    }

    // Suppression
    let enrichedVars = global.get("enrichedVars", "file") || {};
    delete enrichedVars[varToDelete];
    delete enrichedVars[""];
    global.set("enrichedVars", enrichedVars, "file");
    global.set(varToDelete, undefined, "default");
    flow.set("varSelected", "none");
    flow.set("pendingDeletion", null);

    msg.payload = "none";
    msg.info = `✅ Variable "${varToDelete}" supprimée.`;
    msg.notification = {
        type: "success",
        title: "✅ Supprimée",
        text: `Variable "${varToDelete}" supprimée avec succès.`,
        duration: 3000
    };

} else if (msg.payload === "dismiss_clicked") {
    flow.set("pendingDeletion", null);
    msg.info = "❌ Suppression annulée.";
    msg.notification = {
        type: "info",
        title: "❌ Annulée",
        text: "Suppression annulée.",
        duration: 3000
    };
}

return msg;

// open-dialog -> Preparation d'une Boite de Dialogue Suppression
// les actions dans ui-notification doivent être configuré selon un schéma précis
const varSelected = flow.get("varSelected") || null;

if (!varSelected || varSelected === "none" || varSelected === "new") {
    msg.payload = {
        type: "warning", 
        title: "Aucune variable",
        text: "Veuillez sélectionner une variable à supprimer.",
        duration: 3000
    };
    return msg;
}

flow.set("pendingDeletion", varSelected);
// gestion dynamique du ui-notification, les mots clefs de ui-update sont spécifique au noeud
msg.payload = {
    type: "warning",
    title: "Confirmation suppression",
    text: `Voulez-vous vraiment supprimer la variable "<strong>${varSelected}</strong>" ?`,
    displayTime: 0, // Ne pas fermer automatiquement
    ui_update: {
        allowConfirm: true,
        allowDismiss: true,
        confirmText: "✅ Supprimer",
        dismissText: "❌ Annuler"
    }
};

return msg;

// 🔄 Fonctions utilitaires existantes
const storeDefault = "default";
const storeFile = "file";

// 🔄 Valeur par défaut selon le type
function defaultForType(type) {
    switch (type) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
}

// 🔄 Conversion string → typé (avec gestion des valeurs par défaut)
function convertFromString(value, type, defaultVal) {
    if (value === null || value === undefined) {
        return defaultVal !== undefined ? convertFromString(defaultVal, type) : defaultForType(type);
    }
    try {
        switch (type) {
            case "int": return parseInt(value, 10);
            case "number": return parseFloat(value);
            case "boolean": return (value === true || value === "true");
            case "string": return String(value);
            case "array": return Array.isArray(value) ? value : JSON.parse(value);
            case "object": return typeof value === "object" ? value : JSON.parse(value);
            case "date": return new Date(value);
            default: return value;
        }
    } catch (err) {
        node.error(`Erreur de conversion (${type}): ${err.message} (valeur: ${value})`, msg);
        return defaultForType(type);
    }
}

// 🔄 Fonction principale : chargeEnrichedVarsToMemory
function chargeEnrichedVarsToMemory() {
    // Supprimer enrichedVars du stockage par défaut
    global.set("enrichedVars", undefined, storeDefault);

    // Charger enrichedVars depuis le fichier
    let enrichedVars = global.get("enrichedVars", storeFile) || {};
    if (Object.keys(enrichedVars).length === 0) {
        node.error("⚠️ Aucune donnée enrichedVars trouvée dans le stockage fichier.", msg);
        node.status({ fill: "red", shape: "ring", text: "Échec : données manquantes" });
        return false;
    }

    // Parcourir chaque variable dans enrichedVars
    Object.entries(enrichedVars).forEach(([key, e]) => {
        const instances = e.instances || ["*"];
        const props = e.proprietes || [];
        let variable = {};

        // Parcourir les instances
        instances.forEach(instance => {
            variable[instance] = {};
            props.forEach(prop => {
                const name = prop.nomP;
                const type = prop.typeP;
                const rawValue = prop.valeurs?.[instance];
                const defaultVal = prop.valeurs?.["*"];
                variable[instance][name] = convertFromString(rawValue, type, defaultVal);
            });
        });

        // Ajouter les métadonnées (abréviations, etc.)
        if (e.abbrVarG) variable._abbrVarG = e.abbrVarG;
        if (e.indexInstances) variable._indexInstances = e.indexInstances;

        // Stocker dans les variables globales
        if (instances.length === 1 && instances[0] === "*") {
            global.set(key, variable["*"], storeDefault);
        } else {
            global.set(key, variable, storeDefault);
        }
    });

    node.status({ fill: "green", shape: "dot", text: "✅ enrichedVars chargé en mémoire" });
    node.send({ payload: "Chargement terminé" });
    return true;
}

// 🔄 Appel de la fonction
chargeEnrichedVarsToMemory();
msg.info = "✅ Initialisation enrichie depuis enrichedVars (file) terminée.";
return msg;

